import pexpect
import time
import threading
from base_terminal import BaseTerminal

class HeadlessTerminal(BaseTerminal):
    def __init__(self):
        self.child = pexpect.spawn('bash', dimensions=(24, 80), encoding='utf-8')

        # Start a thread to continuously consume output so the pty buffer doesn't fill up
        self._stop_event = threading.Event()
        self._read_thread = threading.Thread(target=self._read_loop, daemon=True)
        self._read_thread.start()

    def _read_loop(self):
        while not self._stop_event.is_set():
            try:
                # Read output non-blocking, up to 4096 bytes
                self.child.read_nonblocking(size=4096, timeout=0.1)
            except pexpect.TIMEOUT:
                pass
            except pexpect.EOF:
                break
            except Exception:
                break

    def send_keystrokes(self, keystrokes: str, wait_sec: float = 0.0) -> None:
        self.child.send(keystrokes)
        if wait_sec > 0:
            time.sleep(wait_sec)

    def __del__(self):
        self._stop_event.set()
        if hasattr(self, '_read_thread'):
            self._read_thread.join(timeout=1.0)
        if hasattr(self, 'child') and self.child.isalive():
            self.child.terminate(force=True)

