import time
import threading
from base_terminal import BaseTerminal

class HeadlessTerminal(BaseTerminal):
    def __init__(self):
        # Start bash as an interactive shell.
        # It automatically detects the pty and runs interactively, sourcing ~/.bashrc
        self.child = pexpect.spawn('bash', dimensions=(24, 80), encoding='utf-8')

        # We need to continuously read the output so the PTY buffer doesn't fill up
        # and block the child process.
        self._stop_event = threading.Event()
        self._read_thread = threading.Thread(target=self._read_loop)
        self._read_thread.daemon = True
        self._read_thread.start()

    def _read_loop(self):
        while not self._stop_event.is_set():
            try:
                # Continuously consume output
                self.child.read_nonblocking(size=4096, timeout=0.1)
            except pexpect.TIMEOUT:
                pass
            except pexpect.EOF:
                break
            except Exception:
                break

    def send_keystrokes(self, keystrokes: str, wait_sec: float = 0.0) -> None:
        self.child.send(keystrokes)
        if wait_sec > 0:
            time.sleep(wait_sec)

    def __del__(self):
        # Signal the read thread to stop
        self._stop_event.set()

        # Clean up the thread
        try:
            if hasattr(self, '_read_thread') and self._read_thread.is_alive():
                self._read_thread.join(timeout=0.2)
        except Exception:
            pass

        # Clean up the child process
        try:
            if hasattr(self, 'child') and self.child.isalive():
                self.child.terminate(force=True)
        except Exception:
